    reg  [4:0] old_data;

    localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            clk_div2 <= 1'b0;
            current_state <= IDLE;
            ATTN_CLK      <= 1'b0;
            ATTN_DATA     <= 1'b0;
            ATTN_LE       <= 1'b0;
            shift_reg     <= 5'b0;
            bit_count     <= 3'd0;
            old_data      <= 5'b0;
        end else begin
            case (current_state)
            IDLE: begin
                if (data != old_data) begin
                    next_state = SHIFT;
                    shift_reg <= data;
                    bit_count <= 0;
                end else begin
                    next_state = IDLE;
                end
            end
            LOAD: begin
                next_state = SHIFT;
                ATTN_CLK <= 1'b1;
                ATTN_DATA <= shift_reg[0];
                ATTN_LE <= 1'b0;
                bit_count <= 1;
            end
            SHIFT: begin
                ATTN_CLK <= 1'b1;
                ATTN_DATA <= shift_reg[bit_count];
                ATTN_LE <= 1'b0;
                bit_count <= bit_count - 1;
                if (bit_count == 0) begin
                    next_state = LATCH;
                end else begin
                    next_state = SHIFT;
                end
            end
            LATCH: begin
                ATTN_CLK <= 1'b0;
                ATTN_DATA <= shift_reg[bit_count];
                ATTN_LE <= 1'b1;
                bit_count <= bit_count - 1;
                if (bit_count == 0) begin
                    next_state = LATCH;
                end else begin
                    next_state = SHIFT;
                end
            end
            endcase
        end
    end

endmodule

