output.rtl/bcd_counter.sv:
module bcd_counter (
    input wire clk,
    input wire rst,
    output reg [3:0] ms_hr,
    output reg [3:0] ls_hr,
    output reg [3:0] ms_min,
    output reg [3:0] ls_min,
    output reg [3:0] ms_sec,
    output reg [3:0] ls_sec
);

reg [3:0] count_sec;
reg [3:0] count_min;
reg [3:0] count_hr;

always @(posedge clk or negedge rst) begin
    if (rst)
        ms_hr <= 0;
        ms_min <= 0;
        ms_sec <= 0;
        ls_hr <= 0;
        ls_min <= 0;
        ls_sec <= 0;
    else
        count_sec <= count_sec + 1;

        if (count_sec == 60) begin
            count_sec <= 0;
            count_min <= count_min + 1;
        end else begin
            count_min <= count_min + 1;
        end

        if (count_min == 60) begin
            count_min <= 0;
            count_hr <= count_hr + 1;
        end else begin
            count_hr <= count_hr + 1;
        end

        if (count_hr == 24) begin
            count_hr <= 0;
        end

        // Convert counts to BCD? We can leave them as decimal and let the display handle BCD, or we can encode as BCD.
        // For simplicity, we output the counters directly.

        // However, the output lines are the digits.

        ms_hr = count_hr;
        ls_hr = count_hr & 1;
        ms_min = count_min;
        ls_min = count_min & 1;
        ms_sec = count_sec;
        ls_sec = count_sec & 1;

endalways

endmodule

output.rtl/bcd_to_excess_3.sv:
module bcd_to_excess_3 (
    input       bcd,
    output reg [3:0] excess3,
    output reg error
);

always @(bcd) begin
    if (bcd < 10) begin
        excess3 <= bcd + 3;
        error <= 0;
    end else begin
        excess3 <= 4'b0000;
        error <= 1;
    end
end

endmodule

input.rtl/bcd_to_excess_3.sv:
`timescale 1ns / 1ps
module bcd_to_excess_3(
    input [3:0] bcd,          // 4-bit BCD input
    output reg [3:0] excess3, // 4-bit Excess-3 output
    output reg error          // Error flag to indicate invalid input
);

// The always block triggers on any change to the BCD input.
always @(bcd)
begin
    error = 1'b0; 
    case(bcd)
        4'b0000: excess3 = 4'b0011;  
        4'b0001: excess3 = 4'b0100;  
        4'b0010: excess3 = 4'b0101;  
        4'b0011: excess3 = 4'b0110;  
        4'b0100: excess3 = 4'b0111;  
        4'b0101: excess3 = 4'b1000;  
        4'b0110: excess3 = 4'b1001;  
        4'b0111: excess3 = 4'b1010;  
        4'b1000: excess3 = 4'b1011;  
        4'b1001: excess3 = 4'b1100;  
        default: begin
            excess3 = 4'b0000;   // Set output to 0 on invalid input.
            error = 1'b1;        // Set error flag to 1 to indicate an invalid input was received.
        end
    endcase
end
endmodule

output.rtl/bcd_to_excess_3.sv:
`timescale 1ns / 1ps

module bcd_to_excess_3 (
    input [3:0] bcd,
    output reg [3:0] excess3,
    output reg error,
    output reg parity,
    output reg [1:0] error_code
);

    localparam u_en = $random; // Simulate random enable generation (optional)

    assign error_code = (enable) ? (bcd < 10) ? 2'b00 : 2'b01 : 2'b10;

    always @(posedge clk) begin
        if (~rst) begin
            excess3 <= 4'b0000;
            error <= 1'b0;
            parity <= 1'b0;
            error_code <= 2'b00;
        end else begin
            if (enable) begin
                if (bcd >= 0 && bcd <= 9) begin
                    // Convert BCD to excess3 using a case statement
                    case (bcd)
                        4'b0000: excess3 = 4'b0011;   // 0 decimal
                        4'b0001: excess3 = 4'b0100;   // 1 decimal
                        4'b0010: excess3 = 4'b0101;   // 2 decimal
                        4'b0011: excess3 = 4'b0110;   // 3 decimal
                        4'b0100: excess3 = 4'b0111;   // 4 decimal
                        4'b0101: excess3 = 4'b1000;   // 5 decimal
                        4'b0110: excess3 = 4'b1001;   // 6 decimal
                        4'b0111: excess3 = 4'b1010;   // 7 decimal
                        4'b1000: excess3 = 4'b1011;   // 8 decimal
                        4'b1001: excess3 = 4'b1100;   // 9 decimal
                        4'b1010: excess3 = 4'b1101;   // A hexadecimal
                        4'b1011: excess3 = 4'b1110;   // B hexadecimal
                        4'b1100: excess3 = 4'b1111;   // C hexadecimal
                        4'b1101: excess3 = 4'b1111;   // D hexadecimal
                        4'b1110: excess3 = 4'b1111;   // E hexadecimal
                        4'b1111: excess3 = 4'b1111;   // F hexadecimal
                    endcase
                end else begin
                    excess3 <= 4'b0000;
                    error <= 1'b1;
                    parity <= 1'b0;
                    error_code = 2'b01;
                end
            end else begin
                excess3 <= 4'b0000;
                error <= 1'b0;
                parity <= 1'b0;
                error_code <= 2'b00;
            end
        end
    end

endmodule

