    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // Dynamic fee adjustment based on hour of day
    always @(*) begin
        if (hour_of_day >= 8 && hour_of_day <= 18) begin
            dynamic_parking_fee = PARKING_FEE_VALUE * 2; // Peak hours: double the fee
        end else begin
            dynamic_parking_fee = PARKING_FEE_VALUE; // Regular hours
        end
    end

    // Next state logic and outputs
    always @(*) begin
        // Defaults
        next_state = state;
        case (state)
            IDLE: begin
                if (vehicle_entry_sensor && available_spaces > 0) begin
                    next_state = ENTRY_PROCESSING;
                end else if (vehicle_exit_sensor && count_car > 0) begin
                    next_state = EXIT_PROCESSING;
                end else if (available_spaces == 0) begin
                    next_state = FULL;
                end
            end
            ENTRY_PROCESSING: begin
                next_state = IDLE;
            end
            EXIT_PROCESSING: begin
                if(clear)
                    next_state <= IDLE;
                else if(time_warning_alert == 1'b1)
                    next_state <= EXIT_PROCESSING;
                else
                    next_state = IDLE;
            end
            FULL: begin
                next_state = (vehicle_exit_sensor) ? EXIT_PROCESSING : FULL;
            end
        endcase
    end

    // LED Status Control
    always @(*) begin
        led_status <= (state != FULL);
    end

    // Space and count management
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            available_spaces <= TOTAL_SPACES;
            count_car <= 0;
            for (i = 0; i < TOTAL_SPACES; i = i + 1) begin
                entry_time[i] <= 0;
            end
        end else begin
            if (state == ENTRY_PROCESSING) begin
                entry_time[current_slot] <= current_time; // Store the entry time based on slot
                available_spaces <= available_spaces - 1;
                count_car <= count_car + 1;
            end else if (state == EXIT_PROCESSING) begin
                    entry_time[current_slot] <= 0; // Clear the slot
                available_spaces <= available_spaces + 1;
                count_car <= count_car - 1;
            end else begin
                available_spaces <= available_spaces;
                count_car <= count_car;
            end
        end
    end

assign time_warning_alert = ((current_time - entry_time[current_slot]) > WARNING_LIMIT && (current_time - entry_time[current_slot]) < OVERSTAY_LIMIT) & !clear ? 1'b1 : 1'b0;

always @(posedge clk) begin
    if (state == EXIT_PROCESSING) begin
        // If parked time exceeds WARNING_LIMIT but is less than OVERSTAY_LIMIT, trigger alert
        if(time_warning_alert == 1)begin
            #5 led_warning <= ~led_warning;
        end else begin
            led_warning <= 0;
        end
    end else begin
        led_warning <= 0;
    end
end



    always@(posedge clk) begin
        if(state == EXIT_PROCESSING) begin
            if (calculate_fee(current_time - entry_time[current_slot], dynamic_parking_fee) > MAX_DAILY_FEE) begin
                parking_fee <= MAX_DAILY_FEE; // Cap fee at maximum daily value
                qr_code <= generate_qr_code(MAX_DAILY_FEE, current_slot, current_time - entry_time[current_slot]); // Generate QR code with time spent
            end else begin
                parking_fee <= calculate_fee(current_time - entry_time[current_slot], dynamic_parking_fee); // Calculate fee
                qr_code <= generate_qr_code(calculate_fee(current_time - entry_time[current_slot], dynamic_parking_fee), current_slot, current_time - entry_time[current_slot]); // Generate QR code with time spent
            end
        end else begin
            parking_fee <= 0;
            qr_code <= 128'b0; // Clear QR code data
        end
    end

    always@(posedge clk) begin
        fee_ready <= (state == EXIT_PROCESSING);
    end

    // Seven-segment display update
    always @(*) begin
        seven_seg_display_available_tens = seven_segment_encoding(available_spaces / 10);
        seven_seg_display_available_units = seven_segment_encoding(available_spaces % 10);
        seven_seg_display_count_tens = seven_segment_encoding(count_car / 10);
        seven_seg_display_count_units = seven_segment_encoding(count_car % 10);
    end

endmodule

