    reg [COEFF_WIDTH*NUM_TAPS-1:0] convolution_result;
    reg valid_out;

    initial begin
        valid_in = 0;
        coeff_array = {};
        in_array = {};
    end

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            valid_in <= 0;
            coeff_array = {};
            in_array = {};
        end else begin
            valid_in <= 1;
            if (valid_in) begin
                // Register data_in and coeffs
                in_array = data_in;
                coeff_array = coeffs;
            end
        end
    end

    // Compute convolution
