    localparam A_IDLE    = 2'd0,
               A_COUNT   = 2'd1,
               A_DONE    = 2'd2;
    // B-domain FSM for measuring "periodB"
    reg [1:0] stateB;
    localparam B_IDLE    = 2'd0,
               B_COUNT   = 2'd1,
               B_DONE    = 2'd2;

    // Clock A FSM
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA <= A_IDLE;
            measure_B <= 0;
            b_count <= 0;
            periodA <= 0;
            done_A <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    if (clk_A) begin
                        measure_A <= 1;
                        measure_B <= 0;
                        b_count <= 0;
                        stateA <= A_COUNT;
                    end
                end
                A_COUNT: begin
                    if (clk_B) begin
                        b_count <= b_count + 1;
                    end
                    if (b_count >= 1000) begin  // arbitrary threshold
                        periodA <= 500;  // example value
                        done_A <= 1;
                        stateA <= A_DONE;
                    end
                end
                A_DONE: begin
                    // No action
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    // Clock B FSM
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB <= B_IDLE;
            measure_A <= 0;
            a_count <= 0;
            periodB <= 0;
            done_B <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    if (clk_B) begin
                        measure_B <= 1;
                        measure_A <= 0;
                        a_count <= 0;
                        stateB <= B_COUNT;
                    end
                end
                B_COUNT: begin
                    if (clk_A) begin
                        a_count <= a_count + 1;
                    end
                    if (a_count >= 1000) begin
                        periodB <= 500;
                        done_B <= 1;
                        stateB <= B_DONE;
                    end
                end
                B_DONE: begin
                    // No action
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // In B-domain, if measure_B=1, increment b_count
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            b_count <= 0;
        end else if (measure_B) begin
            // Increment b_count
            b_count <= b_count + 1;
        end
    end

    // In A-domain, if measure_A=1, increment a_count
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            a_count <= 0;
        end else if (measure_A) begin
            // Increment a_count
            a_count <= a_count + 1;
        end
    end

    // Combine results
    // valid = done_A && done_B
    always @(*) begin
        if (!rst_n) begin
            valid = 0;
            A_faster_than_B = 0;
        end else begin
            valid = (done_A && done_B);
            if (valid) begin
                if (periodA < periodB) A_faster_than_B <= 1;
                else A_faster_than_B <= 0;
            end else A_faster_than_B <= 0;
        end
    end

endmodule

output.rtl/SR_flipflop.sv:
module SR_flipflop(
    input i_S,        // Set input
    input i_R,        // Reset input
    input i_clk,      // Clock input
    input i_rst_b,    // Asynchronous active-low reset input
    output reg o_Q,   // Output Q
    output reg o_Q_b  // Inverted output Q
);

    // Always block triggered on the positive edge of the clock or asynchronous reset
    always @(posedge i_clk or negedge i_rst_b)
    begin
        if (!i_rst_b) // Asynchronous reset active-low
        begin
            o_Q <= 1'b0;  // Set output Q to 0
            o_Q_b <= 1'b1; // Set inverted output Q to 1
        end
        else
        begin
            // Synchronous operation
            if (i_S && !i_R)
            begin
                o_Q <= 1'b1;
                o_Q_b <= 1'b0;
            end else if (!i_S && i_R)
            begin
                o_Q <= 1'b0;
                o_Q_b <= 1'b1;
            end else if (!i_S && !i_R)
            begin
                o_Q <= o_Q;
                o_Q_b <= o_Q_b;
            }
            else // Both high, invalid state
            begin
                o_Q <= 1'b0;
                o_Q_b <= 1'b1;
            }
        end
    end

endmodule

output.rtl/JK_flipflop.sv:
module JK_flipflop(
    input i_J,       // J input of the JK flip-flop
    input i_K,       // K input of the JK flip-flop
    input i_clk,     // Clock input
    input i_rst_b,   // Asynchronous reset, active low
    output reg o_Q,  // Q output
    output reg o_Q_b // Inverted Q output
);

    // Always block triggered on the rising edge of the clock or the falling edge of the reset
    always @(posedge i_clk or negedge i_rst_b) 
    begin
        if (!i_rst_b) // Reset is active
        begin
            o_Q <= 1'b0;   // Set Q to 0
            o_Q_b <= 1'b1; // Set Q_b to 1 (inverted Q)
        end
        else
        begin
            if (i_J == 1 && i_K == 0)
                o_Q = 1'b1;
            else if (i_J == 0 && i_K == 1)
                o_Q = 1'b0;
            else if (i_J == 1 && i_K == 1)
                o_Q = ~o_Q;
            else
                o_Q = o_Q;
        end
    end

endmodule

output.rtl/fsm_seq_detector.sv:
module fsm_sequence_detector (
    input clk_in,
    input rst_in,
    input seq_in,
    output reg seq_detected
);

    localparam num_states = 8;
    state_t cur_state = S0;
    reg seq_detected_flag = 0;

    always_ff @(posedge clk_in) begin
        if (!rst_in) begin
            cur_state <= S0;
            seq_detected_flag <= 0;
        end else begin
            case (cur_state)
                3'b000: // S0, expect '1'
                    if (seq_in == 1'b1) begin
                        cur_state <= 3'b001;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b001: // S1, expect '0'
                    if (seq_in == 1'b0) begin
                        cur_state <= 3'b010;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b010: // S2, expect '1'
                    if (seq_in == 1'b1) begin
                        cur_state <= 3'b011;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b011: // S3, expect '1'
                    if (seq_in == 1'b1) begin
                        cur_state <= 3'b100;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b100: // S4, expect '0'
                    if (seq_in == 1'b0) begin
                        cur_state <= 3'b101;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b101: // S5, expect '0'
                    if (seq_in == 1'b0) begin
                        cur_state <= 3'b110;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b110: // S6, expect '0'
                    if (seq_in == 1'b0) begin
                        cur_state <= 3'b111;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
                endcase
                3'b111: // S7, expect '1'
                    if (seq_in == 1'b1) begin
                        cur_state <= 3'b000;
                        seq_detected_flag <= 1;
                    end else begin
                        cur_state <= 3'b000;
                    end
                    seq_detected_flag <= 0;
            endcase
        end
    end

    always_comb begin
        seq_detected = seq_detected_flag;
    end

endmodule

