    gcd_datapath uut_datapath (.WIDTH(WIDTH), .clk(clk), .rst(rst), .A(A), .B(B), .OUT(out), .EQ(equal), .GREATER(greater_than), .CONTROLPATH_STATE(.controlpath_state), .DONE(.done));

