    // Compute parity checks
    wire c1 = data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
    wire c2 = data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
    wire c3 = data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

    // Determine error location
    if (c1 == 1) data_out[0] = ~data_in[0];
    else if (c2 == 1) data_out[1] = ~data_in[1];
    else if (c3 == 1) data_out[2] = ~data_in[2];
    else data_out = data_in;
  end
endmodule

input.rtl/hamming_tx.sv:
module hamming_code_tx_for_4bit( 
  input[3:0] data_in,
  output[7:0] data_out
);
  assign data_out[0] = 1'b0;
  assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3]; // 2^0
  assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3]; // 2^1
  assign data_out[3] = data_in[0];
  assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3]; // 2^2
  assign data_out[5] = data_in[1];
  assign data_out[6] = data_in[2];
  assign data_out[7] = data_in[3];
endmodule

