module hamming_code_receiver (
  input[7:0] data_in,
  output [3:0] data_out
);

  wire c1,c2,c3,error;
  reg[7:0] correct_data;


  assign c3 =  data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
  assign c2 =  data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
  assign c1 =  data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  assign error = ({c3,c2,c1}==3'b000) ? 1'b0 : 1'b1;

  always@(*)
  begin
    correct_data = 0;
    if(error)
    begin
      correct_data             = data_in;
      correct_data[{c1,c2,c3}] = ~correct_data[{c1,c2,c3}];
    end
    else
    begin
      correct_data             = data_in;
    end
  end

 assign data_out = {correct_data[7],correct_data[6],correct_data[5],correct_data[3]};

endmodule

output.rtl/hamming_rx.sv:
module hamming_rx #(
    parameter int data_width = 4,
    parameter int parity_bits = 3
) (
    input [data_width-1:0] data_in,
    output [data_width-1:0] data_out
);

    // Internal signals
    reg [3:0] data_out_reg;
    reg [PARITY_BIT-1:0] parity;
    reg error;

    // Calculate parity
    initial begin
        parity = {};
        for (int i = 0; i < PARITY_BIT; i++) begin
            parity[i] = xor_combine(data_in[i]);
        end
    end

    // Error detection
    always_ff @(posedge clock) begin
        error = (~parity[PARITY_BIT-1]) ? 1'b1 : 1'b0;
    end

    // Correction
    always_comb begin
        data_out_reg = 0;
        if (error) begin
            data_out_reg = data_in;
        end else begin
            data_out_reg = data_in;
        end
    end

    assign data_out = {data_out_reg[7], data_out_reg[6], data_out_reg[5], data_out_reg[3]};

endmodule

output.rtl/hamming_tx.sv:
module hamming_tx #(
    parameter DATA_WIDTH = 64,
    parameter PART_WIDTH = 4,
    parameter PARITY_BIT = 3
)(
    input  [DATA_WIDTH-1:0]    data_in,
    output [TOTAL_ENCODED-1:0] data_out
);

    localparam num_modules = DATA_WIDTH / PART_WIDTH;
    localparam num_instances = num_modules;

    t_hamming_tx #(
        .DATA_WIDTH(PART_WIDTH),
        .PARITY_BIT(PARITY_BIT),
        .ENCODED_DATA(ENCODED_DATA)
    ) inst1(.data_in(data_in[0:(DATA_WIDTH - 1) / PART_WIDTH]), .data_out(inst1.data_out));

    for (localvar i = 0; i < num_instances - 1; i++) begin : inner_loop
        t_hamming_tx inst_i(.data_in(data_in[(i*PART_WIDTH)+1:(i+1)*PART_WIDTH - 1]), .data_out(inst_i.data_out));
    end

    initial begin
        data_out = 0;
        for (localvar i = 0; i < num_instances; i++) begin
            data_out = data_out ^ inst_i.data_out;
        end
    end

endmodule

module t_hamming_tx #(
    parameter DATA_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1,
    parameter ENCODED_DATA_BIT = $clog2(ENCODED_DATA)
)(
    input  [DATA_WIDTH-1:0]       data_in,
    output  reg[ENCODED_DATA-1:0] data_out
);

    reg [PARITY_BIT-1:0] parity;
    integer i, j, count;
    reg [ENCODED_DATA_BIT:0] pos;

    always @(*) begin
        data_out = {ENCODED_DATA{1'b0}};
        parity   = {PARITY_BIT{1'b0}};
        count    = 0;

        for (pos = 1; pos < ENCODED_DATA; pos = pos + 1) begin
            if (count < DATA_WIDTH) begin
                if ((pos & (pos - 1)) != 0) begin
                    data_out[pos] = data_in[count];
                    count = count + 1;
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            for (i = 1; i <= ENCODED_DATA-1; i = i + 1) begin
                if ((i & (1 << j)) != 0) begin
                    parity[j] = parity[j] ^ data_out[i];
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            data_out[(1 << j)] = parity[j];
        end
    end

endmodule

