module interrupt_controller #(
    parameter NUM_INTERRUPTS = 4, 
    parameter ADDR_WIDTH = 8)
(
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,
    input  logic [NUM_INTERRUPTS-1:0] priority_map_value [NUM_INTERRUPTS-1:0],
    input  logic                      priority_map_update,
    input  logic [ADDR_WIDTH-1:0]     vector_table_value [NUM_INTERRUPTS-1:0],
    input  logic                      vector_table_update,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_mask_value,
    input  logic                      interrupt_mask_update
);

    logic [NUM_INTERRUPTS-1:0] pending_interrupts;
    logic [NUM_INTERRUPTS-1:0] mask;
    logic [NUM_INTERRUPTS-1:0] priority;
    logic [NUM_INTERRUPTS-1:0] selected_index;

    initial begin
        rst_n ?
            ($display("RST"));
        else
            pending_interrupts <= 0;
            mask <= 0;
            priority <= 0;
            selected_index <= 0;
        end
    end

    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            pending_interrupts <= 0;
            interrupt_service <= 0;
            cpu_interrupt <= 0;
            cpu_ack <= 0;
            interrupt_vector <= 0;
            priority_map_value <= {{{NUM_INTERRUPTS*NUM_INTERRUPTS, 1}}};
            vector_table_value <= {{{ADDR_WIDTH*NUM_INTERRUPTS, 1}}};
            interrupt_mask_value <= 0;
            interrupt_mask <= 0;
            selected_index <= 0;
        } else begin
            // Evaluate pending interrupts
            pending_interrupts = interrupt_requests;
            mask = interrupt_mask_value;
            selected_index = -1;
            for (int i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
                if (pending_interrupts[i] && ~mask[i]) begin
                    if (selected_index == -1 || priority[i] < priority[selected_index]) begin
                        selected_index = i;
                    end
                end
            end

            if (selected_index != -1) begin
                interrupt_service <= (interrupt_service == 1'b1) ? 0 : 1'b1;
                cpu_interrupt <= 1'b1;
                interrupt_vector <= vector_table[selected_index];
                cpu_ack <= 1'b0;
            end else begin
                interrupt_service <= 0;
                cpu_interrupt <= 0;
                cpu_ack <= 0;
            end
        end
    end

endmodule

output.rtl/pic_starvation_prevention.sv:
module interrupt_controller (
    input wire clk,
    input wire rst_n,
    input wire reset_interrupts,
    input wire [9:0] interrupt_requests,
    input wire interrupt_ack,
    input wire interrupt_trig,
    input wire [9:0] interrupt_mask,
    input wire [3:0] priority_override,
    input wire [3:0] override_interrupt_id,
    input wire priority_override_en,
    output reg [3:0] interrupt_id,
    output reg interrupt_valid,
    output reg [9:0] interrupt_status,
    output reg [9:0] missed_interrupts,
    output reg starvation_detected
);

    parameter STARVATION_THRESHOLD = 5;

    reg [2:0] current_state;
    reg [9:0] pending_interrupts;
    reg [3:0] wait_counters [0:9];
    reg [4:0] effective_priority [0:9];
    reg [9:0] active_mask;
    reg [3:0] service_timer;
    reg timeout_error;
    reg [3:0] next_interrupt_id;
    reg [4:0] max_priority;

    always @(posedge clk or posedge reset_interrupts) begin
        if (rst_n) begin
            current_state <= IDLE;
            pending_interrupts <= 0;
            wait_counters[0:9] = 0;
            effective_priority[0:9] = 0;
            active_mask <= 0;
            service_timer <= 0;
            timeout_error <= 0;
            next_interrupt_id <= 0;
            max_priority <= 0;
            interrupt_id <= 0;
            interrupt_valid <= 0;
            interrupt_status <= 0;
            missed_interrupts <= 0;
            starvation_detected <= 0;
        end else begin
            case (current_state)
                IDLE: begin
                    next_state = PRIORITY_CALC;
                end

                PRIORITY_CALC: begin
                    next_state = SERVICE_PREP;
                end

                SERVICE_PREP: begin
                    next_state = SERVICING;
                end

                SERVICING: begin
                    // handle timeout
                    timeout_error <= false;
                    if (timeout_error) begin
                        next_state = COMPLETION;
                    end else if (interrupt_valid) begin
                        next_state = COMPLETION;
                    end else begin
                        next_state = SERVICING;
                    end
                end

                COMPLETION: begin
                    interrupt_valid <= 0;
                    next_state = IDLE;
                end

                ERROR: begin
                    next_state = COMPLETION;
                end

                default: next_state = IDLE;
            endcase
        end
    end

endmodule

