output.rtl/moving_average.v:
module moving_average(
    input         clk,
    input         reset,
    input [11:0] data_in,
    output [11:0] data_out
);

    // Internal registers
    reg [11:0] buffer[7]; // 8 elements
    reg [11:0] sum;
    reg full;
    reg [15:0] avg;

    initial begin
        sum = 0;
        full = 0;
        avg = 0;
    end

    always @(posedge clk) begin
        if (~reset) begin
            // Reset on active high reset
            buffer[0] <= 0;
            sum <= 0;
            full <= 0;
            avg <= 0;
        end else begin
            // Process data_in
            if (data_in != 0) begin
                // Shift in new data and shift out oldest
                for (int i = 0; i < 7; i++) begin
                    buffer[i+1] <= buffer[i];
                end
                buffer[7] <= data_in;
                full = 1;
            end else begin
                // If no data, do nothing
            end
        end

        // Compute average
        if (full == 1) begin
            sum = {7{sum[7:0]}};
            avg = sum / 8;
        end
    end

endmodule

input.rtl/moving_average.v:
module moving_average(
    input wire clk,
    input wire reset,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2  : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

assign next_address=write_address + 1'b1;
assign data_out=sum[14 : 3];

    // write current input to memory
    integer i;
    always @(posedge clk ) begin
        if (reset == 1'b1) begin
            for (i = 0 ;i < 8 ; i = i + 1 ) begin
                memory[i]<='h0;
            end
        end else begin
            memory[write_address]<=data_in;
        end
    end

    // read the oldest element written to memory
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            read_data<='h0;
        end else begin
            read_data<=memory[next_address];
        end
    end

    // increase the write address to move onto the next data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            write_address<='h0;
        end else begin
            write_address<=write_address + 1'b1;
        end
    end

    // calculate sum by adding the latest data to the sum and substracting the oldest data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            sum<='h0;
        end else begin
            sum<=sum+data_in-read_data;
        end
    end

endmodule

