module mux_synch (
    input [7:0] data_in,
    input req,
    input dst_clk,
    input src_clk,
    input nrst,
    output reg [7:0] data_out
);

    // Synchronise the request signal to the destination clock domain
    assign req_sync = (dst_clk & ~src_clk) & req;

    // Use a simple multiplexer to select the input data
    assign data_out = (req_sync) ? data_in : 8'b0;

endmodule

module nff (
    input d_in,
    input dst_clk,
    input rst,
    output reg syncd
);

    reg [1:0] sync_reg;
    reg ready;

    always @(posedge dst_clk) begin
        ready <= ~rst;
        if (!ready) begin
            sync_reg <= 2'b00;
        end else if (sync_reg != 8'b00) begin
            sync_reg <= {d_in, 1'b0};
        end else begin
            sync_reg <= sync_reg;
        end
        syncd <= sync_reg[1];
    end

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(
    parameter DATA_WIDTH = 64
) (
    input logic [DATA_WIDTH-1:0] data_in,
    input logic sel,
    output logic [DATA_WIDTH-1:0] data_out
);

always @(*) begin
    if (sel == 0) begin
        data_out = data_in;
    end else if (sel == 1) begin
        logic [DATA_WIDTH/2-1:0] half1, half2;
        half1 = data_in[0:(DATA_WIDTH/2)];
        half2 = data_in[(DATA_WIDTH/2):];
        data_out = reverse(half1) + reverse(half2);
    end else if (sel == 2) begin
        logic [DATA_WIDTH/4-1:0] quarter1, quarter2, quarter3, quarter4;
        quarter1 = data_in[0:(DATA_WIDTH/4)];
        quarter2 = data_in[(DATA_WIDTH/4):(DATA_WIDTH/2)];
        quarter3 = data_in[(DATA_WIDTH/2):(3*DATA_WIDTH/4)];
        quarter4 = data_in[(3*DATA_WIDTH/4):];
        data_out = reverse(quarter1) + reverse(quarter2) + reverse(quarter3) + reverse(quarter4);
    end else if (sel == 3) begin
        logic [DATA_WIDTH/8-1:0] eighth1, eighth2, eighth3, eighth4, eighth5, eighth6, eighth7, eighth8;
        eighth1 = data_in[0:(DATA_WIDTH/8)];
        eighth2 = data_in[(DATA_WIDTH/8):(DATA_WIDTH/4)];
        eighth3 = data_in[(DATA_WIDTH/4):(DATA_WIDTH/2)];
        eighth4 = data_in[(DATA_WIDTH/2):(3*DATA_WIDTH/8)];
        eighth5 = data_in[(3*DATA_WIDTH/8):(7*DATA_WIDTH/8)];
        eighth6 = data_in[(7*DATA_WIDTH/8):(15*DATA_WIDTH/8)];
        eighth7 = data_in[(15*DATA_WIDTH/8):(31*DATA_WIDTH/16)];
        eighth8 = data_in[(31*DATA_WIDTH/16):];
        data_out = reverse(eighth1) + reverse(eighth2) + reverse(eighth3) + reverse(eighth4) + reverse(eighth5) + reverse(eighth6) + reverse(eighth7) + reverse(eighth8);
    end
end

endmodule

input.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64)(
    input [DATA_WIDTH-1:0] data_in,                                         // Input data of size DATA_WIDTH 
    input [1:0] sel,                	                                    //  2-bit selection signal 
    output reg [DATA_WIDTH-1:0] data_out                                    // Output data of size DATA_WIDTH 
);

integer i; 

always @(*) begin
    case(sel)
        2'b00: begin
            for (i = 0; i < DATA_WIDTH; i = i + 1) begin
                data_out[i] = data_in[DATA_WIDTH-1-i];                      
            end
        end

        2'b01: begin
            for (i = 0; i < DATA_WIDTH/2; i = i + 1) begin
                data_out[i]                = data_in[DATA_WIDTH/2-1-i];     
                data_out[DATA_WIDTH/2 + i] = data_in[DATA_WIDTH-1-i];       
            end
        end

        2'b10: begin
            for (i = 0; i < DATA_WIDTH/4; i = i + 1) begin
                data_out[i] = data_in[DATA_WIDTH/4-1-i]; 		            
                data_out[DATA_WIDTH/4 + i]   = data_in[DATA_WIDTH/2-1-i];   
                data_out[DATA_WIDTH/2 + i]   = data_in[3*DATA_WIDTH/4-1-i]; 
                data_out[3*DATA_WIDTH/4 + i] = data_in[DATA_WIDTH-1-i];     
            end
        end

        2'b11: begin
            for (i = 0; i < DATA_WIDTH/8; i = i + 1) begin
                data_out[i]                  = data_in[DATA_WIDTH/8-1-i];   
                data_out[DATA_WIDTH/8 + i]   = data_in[DATA_WIDTH/4-1-i];   
                data_out[DATA_WIDTH/4 + i]   = data_in[3*DATA_WIDTH/8-1-i]; 
                data_out[3*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH/2-1-i];   
                data_out[DATA_WIDTH/2 + i]   = data_in[5*DATA_WIDTH/8-1-i]; 
                data_out[5*DATA_WIDTH/8 + i] = data_in[3*DATA_WIDTH/4-1-i]; 
                data_out[3*DATA_WIDTH/4 + i] = data_in[7*DATA_WIDTH/8-1-i]; 
                data_out[7*DATA_WIDTH/8 + i] = data_in[DATA_WIDTH-1-i];     
            end
        end
        default: begin
            data_out = data_in;						                        
        end
    endcase
end

endmodule

output.rtl/nbit_swizzling.sv:
module nbit_swizzling #(parameter DATA_WIDTH = 64)(
    input [DATA_WIDTH-1:0] data_in,
    input [1:0] sel,
    output reg [DATA_WIDTH-1:0] data_out
);

integer i;

always @(*) begin
    int parity = 0;
    for (i = 0; i < DATA_WIDTH; i = i + 1) begin
        parity ^= data_in[i];
    end

    data_out = (DATA_WIDTH > 0) ? (parity << (DATA_WIDTH-1)) | data_in : 0;

end

endmodule

