module perf_counter #(parameter CNT_W = 8) (
    input wire clk,
    input wire reset,
    input wire sw_req_i,
    input wire cpu_trig_i,
    output reg [CNT_W-1:0] p_count_o
);

reg counter;

always @(posedge clk or negedge reset) begin
    if (~reset)
        counter <= 0;
    else
        if (cpu_trig_i)
            counter++;
end

always @(posedge clk) begin
    if (sw_req_i) begin
        p_count_o <= counter;
        counter <= 0;
    end
end

endmodule

output.rtl/perfect_squares_generator.sv:
module perfect_squares_generator (
    input logic clk,
    input logic reset,
    output logic [31:0] sqr_o
);

    localparam MAX_VAL = 32'hFFFFFFFF;
    reg [31:0] n;
    reg [31:0] sqr_val;
    reg remember_reset;

    always @(posedge clk) begin
        remember_reset = ~reset;
        if (remember_reset) begin
            n <= 0;
            sqr_val <= 0;
        end else begin
            if (n == 0) begin
                n <= 1;
                sqr_val = 1;
            end else begin
                n <= n + 1;
                sqr_val = sqr_val + (n * n);
                if (sqr_val > MAX_VAL) sqr_val <= MAX_VAL;
            end
        end
    end

    assign sqr_o = sqr_val;

endmodule

