module copilot_rs_232 (
    clock,
    reset_neg,
    tx_datain_ready,
    Present_Processing_Completed,
    tx_datain,
    tx_transmitter,
    tx_transmitter_valid
);

    // Parameters
    parameter HIGH = 1'b1;
    parameter LOW = 1'b0;
    parameter CLOCK_FREQ = 100000000; // 100MHz
    parameter BAUD_RATE = 115200;     // Default baud rate
    parameter REG_INPUT = 1;
    parameter BAUD_ACC_WIDTH = 16;

    // Inputs
    input reset_neg;
    input clock;
    input tx_datain_ready;
    input Present_Processing_Completed;
    input [7:0] tx_datain;

    // Outputs
    output tx_transmitter;
    output tx_transmitter_valid;

    // Internal signals
    reg tx_transmitter;
    wire baud_pulse;

    // Instantiate the Baud Rate Generator
    baud_rate_generator #(
        .BAUD_ACC_WIDTH(BAUD_ACC_WIDTH),
        .CLOCK_FREQ(CLOCK_FREQ),
        .BAUD_RATE(BAUD_RATE)
    ) baud_gen (
        .clock(clock),
        .reset_neg(reset_neg),
        .enable(tx_transmitter_valid),
        .baud_pulse(baud_pulse)
    );

    // State Machine
    always @(posedge clock or negedge reset_neg) begin
        case (State)
            Idle: begin
                if (tx_datain_ready)
                    State <= Start;
                tx_transmitter = 1'b1;
                baud_pulse <= 0;
            end
            Start: begin
                tx_transmitter = 1'b0;
                State <= Data;
            end
            Data: begin
                tx_transmitter = 1'b1;
                State <= Stop;
            end
            Stop: begin
                tx_transmitter = 1'b1;
                State <= Idle;
            end
        endcase
    end

    // Output multiplexer
    assign tx_transmitter = (State < 4) | (State[3] & MuxBit);
    assign tx_transmitter_valid = tx_transmitter;

endmodule

// Baud Rate Generator Module
module baud_rate_generator #(
    parameter CLOCK_FREQ = 100000000, // 100MHz
    parameter BAUD_RATE = 115200, // Default baud rate
    parameter BAUD_ACC_WIDTH = 16
)
(
    input clock,
    input reset_neg,
    input enable,
    output reg baud_pulse
);

    // Internal signals
    wire [BAUD_ACC_WIDTH:0] baud_inc;
    reg [BAUD_ACC_WIDTH:0] baud_acc;

    // Calculate the baud increment value
    assign baud_inc = ((BAUD_RATE << (BAUD_ACC_WIDTH - 4)) + (CLOCK_FREQ >> 5)) / (CLOCK_FREQ >> 4);

    // Generate baud_pulse on rising edge of clock
    always @(posedge clock) begin
        if (reset_neg) begin
            baud_pulse = 0;
        end else
            baud_pulse = 1;
    end

endmodule

output.rtl/run_length.sv:
module run_length
#(
    parameter DATA_WIDTH = 8                        // Width of the output run-length counter
)
(
    input wire clk,
    input wire reset_n,
    input wire data_in,
    output reg data_out,
    output reg [$clog2(DATA_WIDTH):0] run_value,
    output reg valid
);

    reg [$clog2(DATA_WIDTH):0] run_length;
    reg prev_data_in;


    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            run_length   <= 'b0;           
            run_value    <= 'b0;	       
            prev_data_in <= 1'b0;			               
        end
        else begin
            if (!reset_n) begin
                // This block is redundant, but we can keep it.
            end
            if (data_in == prev_data_in) begin
                run_length++;
            else begin
                run_length = 1;
                run_value <= prev_data_in;
                prev_data_in = data_in;
            end
            if (run_length == DATA_WIDTH) begin
                run_value <= 1'b0;
            }
        end
    end

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            data_out <= 1'b0;
            valid <= 1'b0;
        end else begin
            data_out <= data_in;
            valid <= ~prev_data_in;
        end
    end

endmodule

module parallel_run_length(
    input wire clk,
    input wire reset_n,
    input wire [NUM_STREAMS-1:0] data_in,
    input wire [NUM_STREAMS-1:0] stream_enable,
    output reg [NUM_STREAMS-1:0] data_out,
    output reg [$clog2(DATA_WIDTH):0] run_value,
    output reg [NUM_STREAMS-1:0] valid
);

    reg [$clog2(DATA_WIDTH):0] run_length_per_stream;
    reg prev_data_per_stream;
    reg valid_per_stream;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            for i in 0 to NUM_STREAMS-1 begin
                run_length_per_stream[i] <= 'b0;
                prev_data_per_stream[i] <= 1'b0;
                valid_per_stream[i] <= 1'b0;
            end
        end else begin
            for i in 0 to NUM_STREAMS-1 begin
                if (stream_enable[i] == 1'b1) begin
                    if (data_in[i] == prev_data_per_stream[i]) begin
                        if (run_length_per_stream[i] == (DATA_WIDTH)) begin
                            run_value[i] <= run_length_per_stream[i];
                        end
                        if (run_length_per_stream[i] < (DATA_WIDTH)) begin
                            run_length_per_stream[i] <= run_length_per_stream[i] + 1'b1;
                        end
                        else begin
                            run_length_per_stream[i] <= 1'b1;
                        end
                    end
                    else begin
                        run_value[i] <= run_length_per_stream[i];
                        run_length_per_stream[i] <= 1'b1;
                    end
                    prev_data_per_stream[i] <= data_in[i];
                end
                else begin
                    run_length_per_stream[i] <= 'b0;
                    prev_data_per_stream[i] <= 1'b0;
                    valid_per_stream[i] <= 1'b0;
                end
            end

            // Determine valid outputs
            for i in 0 to NUM_STREAMS-1 begin
                if (stream_enable[i] == 1'b1 && valid_per_stream[i] == 1'b1) begin
                    valid[i] <= 1'b1;
                    data_out[i] <= prev_data_per_stream[i];
                end else begin
                    valid[i] <= 1'b0;
                    data_out[i] <= 1'b0;
                end
            end
        end
    end

endmodule

output.rtl/scrambler.sv:
// Set the LFSR to a known starting value (0x0000) for consistent initial state
localparam LFSR_INIT = 8'h0000;

module scrambler #(
    parameter DATA_WIDTH = 128   // Width of input data
) (
    input  logic                  clk,        // Clock signal
    input  logic                  rst_n,      // Active-low reset
    input  logic [DATA_WIDTH-1:0] data_in,    // Input data
    input  logic [3:0]            mode,       // Mode to select polynomial
    output logic [DATA_WIDTH-1:0] data_out    // Scrambled data
);

    localparam LFSR_WIDTH = 16;    // Width of the LFSR
    localparam [LFSR_WIDTH-1:0] LFSR_INIT = 8'h0000; // Fixed starting value
    // LFSR registers and feedback logic
    logic [LFSR_WIDTH-1:0] lfsr;
    logic feedback;

    // Polynomial selection based on mode
    always_comb begin
        case (mode)
            4'b0000: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-15];                // Mode 0: ( x^{16} + x^{15} + 1 )
            4'b0001: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-14];                // Mode 1: ( x^{16} + x^{14} + 1 )
            4'b0010: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-8] ^ lfsr[1];      // Mode 2: ( x^{16} + x^{8} + x + 1 )
            4'b0011: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-8];                // Mode 3: ( x^{16} + x^{8} + 1 )
            4'b0100: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-13] ^ lfsr[4];      // Mode 4: ( x^{16} + x^{13} + x^2 + 1 )
            4'b0101: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-12];                // Mode 5: ( x^{16} + x^{12} + 1 )
            4'b0110: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[3] ^ lfsr[0];                 // Mode 6: ( x^{16} + x^3 + x + 1 )
            4'b0111: feedback = lfsr[LFSR_WIDTH-16] ^ lfsr[LFSR_WIDTH-11] ^ lfsr[4];      // Mode 7: ( x^{16} + x^{11} + x^4 + 1 )
            default: feedback = lfsr[LFSR_WIDTH-16];                                     // Default:( x^{16} + 1 )
        endcase
    end

    // LFSR shift logic
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            lfsr <= LFSR_INIT; // Initialize LFSR with a fixed value
        end else begin
            lfsr <= {lfsr[LFSR_WIDTH-2:0], feedback};
        end
    end

    // Scramble data block
    genvar i;
    generate
        for (i = 0; i < DATA_WIDTH; i++) begin
            assign data_out[i] = data_in[i] ^ lfsr[i % LFSR_WIDTH];
        end
    endgenerate

endmodule

input.rtl/deinter_block.sv:
module deinter_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter SUB_BLOCKS    = 4,
    parameter DATA_WIDTH    = ROW_COL_WIDTH*ROW_COL_WIDTH,
    parameter OUT_DATA_WIDTH= 16,
    parameter WAIT_CYCLES   = 4
)(
    input  logic clk,
    input  logic rst_n,
    input  logic i_valid,
    input  logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [OUT_DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

localparam CHUNK = 8;
localparam NBW_COUNTER = $clog2(SUB_BLOCKS) + 1;
localparam NBW_COUNTER_SUB_OUT = 2;

localparam OUT_CYCLES = 32;

localparam N_CYCLES = SUB_BLOCKS*DATA_WIDTH/OUT_DATA_WIDTH;
localparam NBW_COUNTER_OUTPUT = $clog2(N_CYCLES);
logic [NBW_COUNTER_OUTPUT-1:0] counter_output;

logic [NBW_COUNTER-1:0] counter_sub_blocks;
logic [NBW_COUNTER_SUB_OUT-1:0] counter_sub_out;

logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_aux [SUB_BLOCKS-1:0];
logic start_intra;

always_ff @(posedge clk or negedge rst_n ) begin
   if(!rst_n) begin
      counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      start_intra <= 0;
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         in_data_reg[i] <= {DATA_WIDTH{1'b0}};
      end
   end
   else begin
      if(i_valid) begin
         in_data_reg[counter_sub_blocks] <= in_data;

         if(counter_sub_blocks == SUB_BLOCKS) begin
            counter_sub_blocks <= {NBW_COUNTER{1'b0}};
         end
         else begin
            start_intra <= 0;
            counter_sub_blocks <= counter_sub_blocks + 1;
         end
      end
      else if(counter_sub_blocks == SUB_BLOCKS) begin
         start_intra        <= 1;
         counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++)
         out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
   end
   else begin
      if(start_intra)
         for(int i = 0; i < SUB_BLOCKS; i++) 
            out_data_intra_block_reg[i] <= in_data_reg[i];
   end
end

logic [WAIT_CYCLES-1:0] start_intra_ff;
logic enable_output;

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      enable_output  <= 0;
      start_intra_ff <= 0;
   end
   else begin
      enable_output <= start_intra_ff[WAIT_CYCLES-1];
      start_intra_ff<= {start_intra_ff[WAIT_CYCLES-1:1],start_intra};
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++)
         out_data_aux[i] <= {DATA_WIDTH{1'b0}};
   end
   else begin
      if(start_intra) begin
         for(int i = 0; i < 32; i++) begin
            out_data_aux[0][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][((i+1)*CHUNK)-1-:CHUNK];
            out_data_aux[1][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+1)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[2][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+2)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[3][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+3)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
         end
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      out_data        <= {DATA_WIDTH{1'b0}};      
      counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b0}};
      counter_output  <= {NBW_COUNTER_OUTPUT{1'b0}};     
   end
   else begin
      counter_sub_out <= counter_sub_out + 1;
      counter_output  <= counter_output  + 1;
      out_data        <= out_data_aux[counter_sub_out][((counter_output%(DATA_WIDTH/OUT_DATA_WIDTH) + 1))*OUT_DATA_WIDTH-1-:OUT_DATA_WIDTH];
   end
end

endmodule

