module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output // 4-bit output
);

integer i;
reg [3:0] sum;  

always @(posedge clk or posedge reset) begin
    if (reset) begin
        correlation_output <= 0;
        sum = 0;  
    end else begin
        sum = 0;  
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + (input_signal[i] & reference_signal[i]); 
        end
    end
end

endmodule

output.rtl/signal_correlator.sv:
module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output
);

    integer i;
    reg [3:0] sum;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            correlation_output = 0;
            sum = 0;
        end else begin
            sum = 0;
            for (i = 0; i < 8; i = i + 1) begin
                if (input_signal[i] == reference_signal[i]) begin
                    sum = sum + 2;
                end
            end
            // Clamp the result to the 4‑bit limit
            if (sum > 15) sum = 15;
        end
    end

endmodule

output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8) (
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

reg [DATA_WIDTH-1:0] result;
reg overflow_flag;
reg [1:0] state;
reg next_state;

always @(posedge i_clk or posedge i_rst_n) begin
    if (!i_rst_n) begin
        state <= 2'b0;
        result <= 0;
        overflow_flag <= 1'b0;
        o_ready <= 1'b0;
        o_status <= 2'b00;
        return;
    end

    case (state)
        2'b00: // IDLE
            if (i_start) begin
                state <= 2'b01;
            end
        endcase

        2'b01: // LOAD
            if (i_enable) begin
                // load operands
                result <= i_operand_a;
                overflow_flag <= 0;
            end
            next_state = 2'b00;
        endcase

        2'b10: // COMPUTE
            if (i_mode == 1'b0) begin
                result = i_operand_a + i_operand_b;
            else begin
                result = i_operand_a - (~i_operand_b);
            end
            overflow_flag = (i_operand_a ^ i_operand_b) && (result[DATA_WIDTH-1] == 1'b1);
            next_state = 2'b11;
        endcase

        2'b11: // OUTPUT
            o_resultant_sum <= result;
            o_overflow <= overflow_flag;
            o_ready <= 1'b1;
            o_status = 2'b10;
            state <= 2'b0;
    endcase
endalways

always @(*) begin
    if (i_clear) begin
        state <= 2'b0;
        overflow_flag <= 1'b0;
        result <= 0;
        o_ready <= 1'b0;
        o_status <= 2'b00;
    end
end

always @(i_start or i_enable) begin
    if (i_rst_n) begin
        state <= 2'b0;
        overflow_flag <= 1'b0;
        result <= 0;
        o_ready <= 1'b0;
        o_status <= 2'b00;
        return;
    end
    if (i_clear) begin
        state <= 2'b0;
        overflow_flag <= 1'b0;
        result <= 0;
        o_ready <= 1'b0;
        o_status <= 2'b00;
        return;
    end
end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8,
    parameter p_max_numbers = 16
)(
    input wire i_clk,
    input wire i_rst_n,
    input wire i_ready,
    input wire [p_bit_width-1:0] i_number,
    output reg [p_bit_width-1:0] o_unique_number
);

reg [p_bit_width-1:0] counts[2^p_bit_width];
reg [p_bit_width-1:0] candidate;

initial begin
    o_unique_number = 0;
    for (int i = 0; i < 2^p_bit_width; i++) begin
        counts[i] = 0;
    end
end

always @(posedge i_clk or posedge i_rst_n) begin
    if (i_rst_n) begin
        o_unique_number = 0;
        for (int i = 0; i < 2^p_bit_width; i++) begin
            counts[i] = 0;
        end
        candidate = 0;
    end else if (i_ready) begin
        counts[i_number]++;
        candidate = 0;
        for (int i = 0; i < 2^p_bit_width; i++) begin
            if (counts[i] == 1) begin
                candidate = i;
                break;
            end
        }
    end
end

always begin
    if (i_ready) begin
        // No action needed
    end
end

endmodule

output.rtl/pipelined_skid_buffer.sv:
module pipelined_skid_buffer(
    input wire clock,
    input wire rst,

    input wire [3:0] data_i,
    input wire valid_i,
    output wire ready_o,
    output wire valid_o,
    output wire [3:0] data_o,
    input wire ready_i

    );

    // Skid buffer instance
    skid_buffer skb (
        .clock(clock),
        .rst(rst),
        .data_i(data_i),
        .valid_i(valid_i),
        .o_ready(ready_o)
    );

    // Register to store data
    reg [3:0] reg_data;

    // Connect skid_buffer output to register input
    assign reg_data = skb.o_data;

    // Registers for data storage
    always @(posedge clock or posedge rst) begin
        if (!rst) begin
            reg_data[3:0] <= 0;
        end else begin
            reg_data[3:0] <= data_o;
        end
    end

    // Outputs
    assign data_o = reg_data[3:0];
    assign valid_o = reg_data[3] == 1'b1;
    assign ready_o = ready_i;

endmodule

module register(
    input clk,
    input rst,

    input [3:0] data_in,
    input valid_in,
    output ready_out,
    output valid_out,
    output [3:0] data_out,
    input ready_in

    );

    reg [3:0] mem;

    always @(posedge clk or posedge rst) begin
        if (!rst) begin
            mem <= 0;
        end else begin
            mem <= data_in;
        end
    end

    assign ready_out = ready_in;
    assign valid_out = (mem != 0);
    assign data_out = mem[3:0];
    assign ready_out = ready_in;

endmodule

module skid_buffer(
    input  clk,
    input  reset ,

    input  [3:0]i_data,
    input  i_valid,
output o_ready,

output [3:0]o_data,
output o_valid,
input  i_ready

);

    reg [3:0] data_reg;
    reg buffer;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_reg <= 0;
            buffer <= 1'b0;
        end else begin
            if (i_valid) begin
                data_reg <= i_data;
                buffer <= 1'b1;
            end else begin
                data_reg <= 0;
                buffer <= 1'b0;
            end
        end
    end

    assign o_ready = buffer;
    assign o_data = data_reg;
    assign o_valid = buffer;
    assign i_ready = i_ready;

endmodule

