module vga_controller (
    input wire clock,
    input wire reset,
    input [7:0] color_in,
    output reg hsync,
    output reg vsync,
    output reg [7:0] red,
    output reg [7:0] green,
    output reg [7:0] blue,
    output reg [9:0] next_x,
    output reg [9:0] next_y,
    output reg sync,
    output reg [3:0] blank,
    output reg [9:0] next_x_next,
    output reg [9:0] next_y_next,
    output reg sync_clk,
    output reg blank_clk
);

// Reset initialization
reg h_counter, v_counter, h_front, h_pulse, h_back;
reg v_counter_val, v_front, v_pulse, v_back;

initial begin
    h_counter = 0;
    v_counter = 0;
    h_front = 640;
    h_pulse = 16;
    h_back = 48;
    v_front = 10;
    v_pulse = 96;
    v_back = 33;
end

always_ff @(posedge clock) begin
    if (~reset) begin
        h_counter <= 0;
        v_counter <= 0;
        h_front <= 640;
        h_pulse <= 16;
        h_back <= 48;
        v_front <= 10;
        v_pulse <= 96;
        v_back <= 33;
        hsync <= 1;
        vsync <= 1;
        red = 0;
        green = 0;
        blue = 0;
        next_x <= 0;
        next_y <= 0;
        sync <= 0;
        blank <= 0;
        next_x_next <= 0;
        next_y_next <= 0;
        sync_clk <= 0;
        blank_clk <= 0;
    end else begin
        case (horizontal_state)
            H_ACTIVE: begin
                if (h_counter < h_front) begin
                    h_counter <= h_counter + 1;
                end else if (h_counter == h_front) begin
                    h_front_done = 1;
                    h_counter <= 0;
                end
            end
            front_porch: begin
                if (h_front_done) begin
                    h_front_done <= 0;
                    h_front_pulse = 16;
                    v_front <= 1;
                    v_counter <= v_counter + 1;
                end else begin
                    h_front_pulse <= 0;
                end
            end
            // more states
        endcase
    end
end

assign hsync = h_front_done ? 1 : 0;
assign vsync = v_front_done ? 1 : 0;

assign red = {color_in[7:5], 5'd0};
assign green = {color_in[4:2], 5'd0};
assign blue = {color_in[1:0], 6'd0};

assign next_x = next_x_next;
assign next_y = next_y_next;

assign sync = hsync;
assign blank = h_front_done || v_front_done;

always_ff @(posedge clock) begin
    if (hsync) begin
        // Generate sync pulses
        if (h_front_done) begin
            vsync <= 1;
        end
        if (h_pulse > 0) begin
            h_pulse <= h_pulse - 1;
        end else begin
            hsync <= 0;
        end
    end
end

endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;

    // Clock and reset
    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;
    logic sync;
    logic clk;
    logic blank;

    // Initialization
    initial begin
        h_counter   <= 10'd0;
        v_counter   <= 10'd0;
        h_state     <= H_ACTIVE_STATE;
        v_state     <= V_ACTIVE_STATE;
        line_done   <= LOW;
    end

    // Always block for clock
    always @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    case (h_counter < H_ACTIVE-1) {
                        h_counter++;
                        hsync <= HIGH;
                    } else {
                        h_state <= H_FRONT_STATE;
                    }
                end
                H_FRONT_STATE: begin
                    case (h_counter < H_FRONT-1) {
                        h_counter++;
                        hsync <= HIGH;
                    } else {
                        h_state <= H_PULSE_STATE;
                    }
                end
                H_PULSE_STATE: begin
                    hsync <= LOW;
                    if (h_counter < H_PULSE-1)
                        h_counter++;
                    else
                        h_state <= H_BACK_STATE;
                end
                H_BACK_STATE: begin
                    hsync <= HIGH;
                    if (h_counter < H_BACK-1)
                        h_counter++;
                    else
                        h_state <= H_ACTIVE_STATE;
                end
            endcase
        end
    end

    case (v_state)
        V_ACTIVE_STATE: begin
            case (v_counter < V_ACTIVE-1) {
                v_counter++;
                vsync <= HIGH;
            } else {
                v_state <= V_FRONT_STATE;
            }
        end
        V_FRONT_STATE: begin
            case (v_counter < V_FRONT-1) {
                v_counter++;
                vsync <= HIGH;
            } else {
                v_state <= V_PULSE_STATE;
            }
        end
        V_PULSE_STATE: begin
            vsync <= LOW;
            if (v_counter < V_PULSE-1)
                v_counter++;
            else
                v_state <= V_BACK_STATE;
        end
        V_BACK_STATE: begin
            vsync <= HIGH;
            v_counter <= 10'd0;
        end
    endcase

    // RGB handling
    always @(*) begin
        if (h_state == H_ACTIVE_STATE) begin
            red   <= color_in[0];
            green <= color_in[1];
            blue  <= color_in[2];
        end else if (v_state == V_ACTIVE_STATE) begin
            red   <= color_in[0];
            green <= color_in[1];
            blue  <= color_in[2];
        end else begin
            red   <= 0;
            green <= 0;
            blue  <= 0;
        end
    end

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

